import{_ as t,o as s,c as n,ag as a}from"./chunks/framework.ePeAWSvT.js";const i="/assets/datahub-endpoint-ai-settings-tab.DxArrkZ8.png",g=JSON.parse('{"title":"AI Settings","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-settings.md","filePath":"guide/ai-settings.md"}'),o={name:"guide/ai-settings.md"};function r(l,e,d,c,h,u){return s(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="ai-settings" tabindex="-1">AI Settings <a class="header-anchor" href="#ai-settings" aria-label="Permalink to &quot;AI Settings&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Within your Central Data Hub, you can select the various Endpoints to view the AI Settings tab. The AI Settings tab enables organizations to extend the value of their data beyond traditional system-to-system integration by making selected data available to AI-driven capabilities within Central. These settings control how data is indexed for AI search and how meaningful activities are identified and surfaced as Business Events.</p><p>AI Settings function independently from core integration logic. Enabling AI features <strong>does not</strong> affect how data is published, subscribed, transformed, or synchronized between systems. Instead, AI Settings determine how data can be discovered, interpreted, and presented once it already exists within Central.</p><p>At a high level, AI Settings support two distinct capabilities:</p><ul><li><strong>AI Search Enablement</strong> — Allows data from publishing Endpoints to be indexed in a format that AI engines can query using natural language.</li><li><strong>Business Events and Pulse</strong> — Allows selected data changes to be promoted as Business Events that surface in Pulse, a personalized activity feed within TeamCentral&#39;s agent platform Corbi.</li></ul><p>These capabilities are configured separately, allowing organizations to precisely control data visibility, search access, and event notifications.</p><p><img src="'+i+'" alt="Endpoint AI Settings Tab"></p><div class="warning custom-block"><p class="custom-block-title">Notes</p><ul><li>Search and Business Events are independent of each other; data can be searchable without generating events, and events can occur without searchable data.</li><li>Endpoints supply the data; Business Events define how that data is presented.</li><li>Pulse is personalized; users only see what they subscribe to and filter for.</li><li>AI Settings do not affect integrations; the core data synchronization remains unchanged.</li></ul></div><div class="info custom-block"><p class="custom-block-title">Note</p><p>AI functionality is intentionally divided between administrative setup and individual personalization.</p><ul><li><strong>Administrators</strong> are responsible for enabling <strong>Send to Search</strong> on publishing Endpoints, defining Business Events, associating Business Events with Endpoints, and establishing event rules and content structure. The configuration of this data determines what data <em>can</em> be searched and what events <em>can</em> be generated.</li><li><strong>End users</strong> control which business events they follow, how events are filtered using tags, and how Pulse displays activity relevant to them. This allows users to receive insights that are meaningful to their role without exposing unnecessary data.</li></ul></div><h2 id="three-layer-model" tabindex="-1">Three-Layer Model <a class="header-anchor" href="#three-layer-model" aria-label="Permalink to &quot;Three-Layer Model&quot;">​</a></h2><p>AI Settings follow a three-layer model that separates data preparation, event definition, and user experience.</p><h3 id="_1-data-preparation-send-to-search" tabindex="-1">1. Data Preparation: Send to Search <a class="header-anchor" href="#_1-data-preparation-send-to-search" aria-label="Permalink to &quot;1. Data Preparation: Send to Search&quot;">​</a></h3><p>At the Endpoint level within the Data Hub, administrators can enable <strong>Send to Search</strong>. When enabled, data published by that Endpoint is indexed so it can be queried by AI-powered tools. This includes <a href="./build-data-models.html">Schema Definitions</a>, Schema Properties, etc. Then, once indexed, the data becomes available to AI agents and conversational interfaces across the platform.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Enabling <strong>Send to Search</strong> simply makes data available for AI-based querying; it does not notify users, trigger alerts, or generate feed items in Corbi.</p></div><h3 id="_2-event-definition-business-events" tabindex="-1">2. Event Definition: Business Events <a class="header-anchor" href="#_2-event-definition-business-events" aria-label="Permalink to &quot;2. Event Definition: Business Events&quot;">​</a></h3><p>Business Events represent meaningful moments within the organization, such as new customers, new opportunities, employee milestones or status changes, etc. Business Events are defined at the corporate level and act as reusable templates that describe what data is relevant, how the event should be formatted, and where it may appear (e.g., app feed, summaries). Then, once defined, a Business Event can be associated with one or more publishing Endpoints through AI Settings. Additionally, optional rules can be applied at the Endpoint level to determine <em>when</em> the event should trigger (e.g. an Endpoint publishing account data may be associated with a <em>New Customer</em> business event, but only trigger when the pipeline status equals <em>Customer</em>).</p><h3 id="_3-user-experience-pulse-and-channels" tabindex="-1">3. User Experience: Pulse and Channels <a class="header-anchor" href="#_3-user-experience-pulse-and-channels" aria-label="Permalink to &quot;3. User Experience: Pulse and Channels&quot;">​</a></h3><p>Business Events display to users through Pulse in the Corbi application. Pulse is a personalized activity feed driven by channels, displaying the Business Events you choose to follow. You can further refine these channels using filters and tags based on the underlying data (such as region, industry, owner, or role). Each user&#39;s Pulse experience is unique, reflecting the business events you subscribe to, how those events are filtered, as well as your role, interests, and permissions.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Business Events are configured centrally, but visibility and relevance of the data are controlled individually by each user within Corbi.</p></div><div class="tip custom-block"><p class="custom-block-title">Best Practices</p><ul><li>Only enable <strong>Send to Search</strong> for data that is appropriate for AI-based discovery. Consider access permissions and data sensitivity when making data searchable.</li><li>Define Business Events broadly at the corporate level, then rely on user-level filters in Corbi to tailor relevance.</li><li>To construct the most effective and resourceful <strong>Pulse</strong> feed, use Endpoint-level rules (e.g. filtering out leads so only customers generate events).</li></ul></div><h2 id="enable-send-to-search" tabindex="-1">Enable Send to Search <a class="header-anchor" href="#enable-send-to-search" aria-label="Permalink to &quot;Enable Send to Search&quot;">​</a></h2><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate <strong>Endpoint</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>The <strong>AI Settings</strong> tab can only be found in publishing Endpoints.</p></div><ol start="3"><li>Select the <strong>AI Settings</strong> tab.</li><li>Toggle <strong>Send to Search</strong> ON.</li><li>Select <strong>Save</strong>.</li></ol><h2 id="import-sync-history" tabindex="-1">Import Sync History <a class="header-anchor" href="#import-sync-history" aria-label="Permalink to &quot;Import Sync History&quot;">​</a></h2><p>Once <strong>Send to Search</strong> is enabled, you can use <strong>Import Sync History</strong> to backfill the search index with historical data. This replays published messages from all publishers of the same transaction type, rebuilding search entities from existing data without affecting integrations or republishing to subscribers.</p><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate <strong>Endpoint</strong>.</li><li>Select the <strong>AI Settings</strong> tab.</li><li>Select <strong>Import Sync History</strong>.</li><li>Set the <strong>Since</strong> date to control how far back to import. Only messages published after this date will be included.</li><li>(Optional) Select <strong>Preview</strong> to see the total number of messages that will be processed. Only the most recent message per entity will be synced.</li><li>Select <strong>Run</strong> to begin the import.</li></ol><p>When the import completes, a summary displays the number of entities successfully synced and any errors. If errors occur, expand the error list to see per-entity details and links to record history.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Import Sync History consolidates data from all sibling publisher endpoints that share the same transaction type, entity type, and Send to Search setting within the Data Hub. Each publisher contributes only the properties defined by its own maps.</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>For large datasets, the import may take several minutes. The modal will remain open and display progress. Do not close the modal while the import is running.</p></div><h2 id="associate-endpoint-with-business-events" tabindex="-1">Associate Endpoint with Business Events <a class="header-anchor" href="#associate-endpoint-with-business-events" aria-label="Permalink to &quot;Associate Endpoint with Business Events&quot;">​</a></h2><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate <strong>Endpoint</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>The <strong>AI Settings</strong> tab can only be found in publishing Endpoints.</p></div><ol start="3"><li>Select the <strong>AI Settings</strong> tab.</li><li>Select an option from the <strong>Business Event Categories</strong> drop-down menu.</li><li>Select <strong>+Add</strong>.</li><li>Select <strong>Save</strong>.</li></ol><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./build-datahubs.html">Building Data Hubs</a> — Create and configure Data Hubs</li><li><a href="./build-business-events.html">Business Events</a> — Define Business Event categories and templates</li><li><a href="./deploy.html">Deployments</a> — Deploy configurations to your environments</li></ul>',37)])])}const b=t(o,[["render",r]]);export{g as __pageData,b as default};
